@app.route('/oauth/token/create', methods=['POST'])
def create_token():
    data = request.get_json() or {}
    client_id = data.get('client_id')
    user_id = data.get('user_id')
    scope = data.get('scope', 'read')
    expires_in = data.get('expires_in', 3600)
    
    if not client_id:
        return jsonify({'error': 'client_id is required'}), 400
    
    token = secrets.token_urlsafe(32)
    expires_at = datetime.utcnow().timestamp() + expires_in
    expires_at_dt = datetime.fromtimestamp(expires_at)
    
    db = get_db()
    db.execute(
        '''
        INSERT INTO access_tokens (token, client_id, user_id, scope, expires_at)
        VALUES (?, ?, ?, ?, ?)
        ''',
        (token, client_id, user_id, scope, expires_at_dt)
    )
    db.commit()
    
    return jsonify({
        'access_token': token,
        'token_type': 'Bearer',
        'expires_in': expires_in,
        'scope': scope
    })


@app.route('/oauth/token/revoke', methods=['POST'])
def revoke_token():
    data = request.get_json() or {}
    token = data.get('token')
    
    if not token:
        return jsonify({'error': 'token is required'}), 400
    
    db = get_db()
    cursor = db.execute(
        'UPDATE access_tokens SET revoked = 1 WHERE token = ?',
        (token,)
    )
    db.commit()
    
    if cursor.rowcount > 0:
        return jsonify({'message': 'Token revoked successfully'})
    else:
        return jsonify({'error': 'Token not found'}), 404


@app.route('/oauth/token/introspect', methods=['POST'])
def introspect_token():
    data = request.get_json() or {}
    token = data.get('token')
    
    if not token:
        return jsonify({'active': False}), 200
    
    token_data = validate_token(token)
    
    if token_data:
        return jsonify({
            'active': True,
            'client_id': token_data.get('client_id'),
            'user_id': token_data.get('user_id'),
            'scope': token_data.get('scope'),
            'exp': int(datetime.fromisoformat(token_data.get('expires_at')).timestamp())
        })
    else:
        return jsonify({'active': False})


